      limit: 3,
    });

    const shortlist = Array.isArray(ranked) ? ranked : [];
    const chosen = shortlist[0] || activeUsPoliticsCandidates[0];

    resolvedMarket = {
      title: chosen.title,
      slug: chosen.slug,
      conditionId: chosen.conditionId,
      url: chosen.url,
      category: chosen.category,
      liquidity: chosen.liquidity,
      volume: chosen.volume,
    };

    finalResult = await callMcpSkill({
      toolId: POLYMARKET_TOOL_ID,
