      args: { conditionId: chosen.conditionId },
    });
    attemptedBranches.push({
      tool: "check_market_rules",
      conditionId: chosen.conditionId,
    });
  }

  const rulesSummary = finalResult?.rulesSummary || {};
  const potentialGotchas = Array.isArray(rulesSummary.potentialGotchas)
    ? rulesSummary.potentialGotchas
    : [];

