    requestedSlug,
    usedFallback,
    resolvedMarket,
    market: finalResult?.market,
    resolvesYesIf: rulesSummary.resolvesYesIf,
    resolvesNoIf: rulesSummary.resolvesNoIf,
    potentialGotchas: potentialGotchas.map((item) => `- ${item}`),
    attemptedBranches,
    fetchedAt: finalResult?.fetchedAt,
