  const tradesSummary = result?.tradesSummary || {};
  const openInterest = result?.openInterest || {};

  const buyVolume = typeof tradesSummary.buyVolume === "number" ? tradesSummary.buyVolume : null;
  const sellVolume = typeof tradesSummary.sellVolume === "number" ? tradesSummary.sellVolume : null;

  let activitySkew = "insufficient data";
  if (buyVolume !== null && sellVolume !== null) {
    if (buyVolume > sellVolume) activitySkew = "buyers";
    else if (sellVolume > buyVolume) activitySkew = "sellers";
    else activitySkew = "balanced";
  }

  return {
    selectedMarketTitle: selectedMarket.title ?? null,
    endDate: selectedMarket.endDate ?? null,
    openInterestValue: openInterest.value ?? null,
    buyVolume,
    sellVolume,
    activitySkew
  };
}

